{
  "schemaVersion": 2,
  "id": "serif-headings-pack",
  "name": "Serif Headings Pack",
  "version": "1.0.0",
  "entry": null,
  "pluginType": "ui-snippet",
  "capabilities": [
    "theme.snippet"
  ],
  "platforms": [
    "desktop",
    "web"
  ],
  "requiresRestart": false,
  "experimental": false,
  "minAppVersion": "0.6.0",
  "maxAppVersion": null,
  "permissions": {
    "theme": {
      "register": true
    }
  },
  "contributes": {
    "theme": {
      "style": [],
      "snippets": [
        {
          "file": "theme/snippets/serif-headings-pack.css",
          "id": "serif-headings-pack",
          "label": "Serif Headings",
          "description": "Serif h1–h2 via NodeView heading selectors.",
          "defaultEnabled": false
        }
      ],
      "tokens": [],
      "defaultEnable": {}
    },
    "commands": [],
    "preferencesSections": [],
    "panels": []
  }
}

/**
 * Serif headings — UI snippet
 *
 * Literary serif titles — pair with paper-ink or any light theme.
 * Targets NodeView headings (.pm-heading-content) + export preview.
 *
 * Copy to ~/.luna/theme/snippets/serif-headings.css → Rescan → enable in UI snippets.
 */

.preview-pane.markdown-visual-editor .ProseMirror .pm-heading-block--l1 .pm-heading-content,
.preview-pane.markdown-visual-editor .ProseMirror .pm-heading-block--l2 .pm-heading-content,
.preview-pane.markdown-visual-editor .ProseMirror > h1,
.preview-pane.markdown-visual-editor .ProseMirror > h2,
.markdown-preview-view h1,
.markdown-preview-view h2 {
  font-family: 'Iowan Old Style', 'Palatino Linotype', Palatino, 'Songti SC', 'Noto Serif SC', serif;
  font-weight: 600;
  letter-spacing: -0.01em;
}

.preview-pane.markdown-visual-editor .ProseMirror .pm-heading-block--l1 .pm-heading-content,
.preview-pane.markdown-visual-editor .ProseMirror > h1,
.markdown-preview-view h1 {
  font-size: 1.65em;
}

.preview-pane.markdown-visual-editor .ProseMirror .pm-heading-block--l2 .pm-heading-content,
.preview-pane.markdown-visual-editor .ProseMirror > h2,
.markdown-preview-view h2 {
  font-size: 1.35em;
}
